// The determinism postcondition requires post1_self_ == post2_self_ at
    // the SMT level. StrictlyOrderedMap<K> contains Vec fields (keys.v,
    // vals); in this Verus version Vec<T> lacks view-based extensionality
    // (we verified: requires v1@ == v2@ ensures v1 == v2 fails), so even
    // though valid() pins the views uniquely, we cannot bridge view equality
    // to abstract Vec equality without an axiom. Hence post1_self_ ==
    // post2_self_ is not derivable inside this proof body under the given
    // hypotheses; the implication holds semantically only modulo that
    // Vec-extensionality axiom which we are not allowed to introduce.
    if post1_self_.valid()
        && post1_self_@ == pre_self_@.insert(k, v)
        && (forall |lo, hi| post1_self_.gap(lo, hi) <==>
                        pre_self_.gap(lo, hi)
                    && !(lo.lt_spec(KeyIterator::new_spec(k))
                      && KeyIterator::new_spec(k).lt_spec(hi)))
        && post2_self_.valid()
        && post2_self_@ == pre_self_@.insert(k, v)
        && (forall |lo, hi| post2_self_.gap(lo, hi) <==>
                        pre_self_.gap(lo, hi)
                    && !(lo.lt_spec(KeyIterator::new_spec(k))
                      && KeyIterator::new_spec(k).lt_spec(hi)))
    {
        assert(post1_self_@ == post2_self_@);
        assert(r1 == r2);
    }
